<template>
  <div v-click-away="closeNotifications" class="relative inline-block text-left">
    <button class="p-2 relative focus:outline-none rounded-full bg-blue-100 text-primary hover:text-white hover:bg-primary" @click="openNotificationsList">
      <Badge v-if="notificationsCount" :content="notificationsCount" />
      <Icon icon="mdi:bell-outline" width="30" />
    </button>
    <div v-if="isOpen" style="z-index: 2000" class="origin-top-right absolute right-0 w-[430px] max-h-[600px] rounded-md shadow-lg bg-white ring-1 ring-black ring-opacity-5 focus:outline-none z-20 overflow-auto flex flex-col gap-4 p-3">
      <button v-if="notificationsList.length" class="px-4 py-1 rounded-md hover:bg-primary hover:text-white transition duration-300" @click="openClearAllModal">
        Барчасини тозалаш
      </button>
      <template v-if="notificationsList.length">
        <NotificationCard v-for="item in notificationsList" :key="item.id" :notify-content="item" @notification-seen="notificationSeen" />
      </template>
      <template v-else>
        <h5>Хабарлар мавжуд эмас!</h5>
      </template>
    </div>
  </div>
  <ModalComponent ref="modalRef" modal-position="center" :close-on-click-away="false" :hide-close-button="true">
    <template #slotBody>
      <div class="p-10 text-3xl flex items-center justify-center">
        <h1>Siz Сиз барча билдиришномаларни тозаламоқчимисиз?</h1>
      </div>
      <div class="flex justify-center">
        <button class="base_input border-primary bg-primary text-white mx-2 hover:opacity-80" @click="modalRef.closeModal">
          Йўқ
        </button>
        <button class="base_input border-primary bg-primary text-white mx-2 hover:opacity-80" @click="clearAllNotifications">
          Ҳа
        </button>
      </div>
    </template>
  </ModalComponent>
</template>

<script setup>
import Badge from "../components/Badge";
import {Icon} from "@iconify/vue";
import ModalComponent from "../components/ModalComponent";
import {defineComponent, onMounted, ref, onBeforeMount, computed, watch} from "vue";
import NotificationCard from "./NotificationCard";
import SockJS from "sockjs-client";
import axios from "../plugins/axios";
import Stomp from "webstomp-client";
import {useStore} from "vuex";


defineComponent({Icon,ModalComponent,NotificationCard,Badge})


onMounted(async()=>{
  await connect()
  await getNotificationsList()
  await getNotificationsCount()
})
const  store = useStore()


const modalRef = ref()
const isOpen = ref(false)
const notificationsCount = ref(null)
const notificationsList = ref([])


 const clearAllNotifications = async ()=>{
  try {
    const payload = {
      ids: notificationsList.value.map(n=>n.id)
    }
    const resp =  (await axios.post(`/api/notification/list`,payload))
    await store.dispatch('toast',{
      type:'success',
      message:resp.message
    })
    modalRef.value.closeModal()
    closeNotifications()
  }catch (e) {
    await store.dispatch('errorHandler',e)
  }
}


async function getNotificationsCount(){
  notificationsCount.value = null
  const resp = (await axios.get('/api/notification/count')).data?.data
  notificationsCount.value  = resp
}

function notifyMe(message) {
  // Проверка поддержки браузером уведомлений
  if (!("Notification" in window)) {
    alert("Ушбу браузерда хабарлар чиқариш имконияти мавжуд эмас");
  }

  // Проверка разрешения на отправку уведомлений
  else if (Notification.permission === "granted") {
    // Если разрешено, то создаём уведомление
    let notification = new Notification(message);
  }

  // В противном случае, запрашиваем разрешение
  else if (Notification.permission !== 'denied') {
    Notification.requestPermission(function (permission) {
      // Если пользователь разрешил, то создаём уведомление
      if (permission === "granted") {
        let notification = new Notification(message);
      }
    });
  }

  // В конечном счёте, если пользователь отказался от получения
  // уведомлений, то стоит уважать его выбор и не беспокоить его
  // по этому поводу.
}


async function getNotificationsList(){
  const resp = (await axios.get('/api/notification/all')).data?.data
  notificationsList.value  = resp
}

async function openNotificationsList(){
  toggleNotifications()
  if(isOpen.value === true){
    await getNotificationsList()
  }
  await getNotificationsCount()
}

function toggleNotifications(){
  isOpen.value = !isOpen.value
}

function closeNotifications(){
  isOpen.value = false
}
async function notificationSeen(){
  closeNotifications()
}

function openClearAllModal(){
  modalRef.value.openModal()
}


const stompClient = ref(null)

async function connect() {
  let socket = new SockJS(`${axios.defaults.baseURL}socket`);
  let stompClient = Stomp.over(socket);
  await stompClient.connect(
      {},
      (frame) => {
        stompClient.subscribe(`/notify/${store.getters['getUserInfo'].id}`, async(tick) => {
          if(tick?.body){
            notifyMe(tick?.body)
            await getNotificationsCount()
          }
        });
      },
      error => {
        console.log(error);
      }
  );
}





</script>

