<template>
  <div class="bg-white flex flex-col gap-4 p-2 border-b border-[#D2D1D1] cursor-pointer" @click="seeNotification">
    <div class="flex justify-between items-center">
      <div class="flex items-center gap-4">
        <Icon v-if="!props.notifyContent.seen" class="text-green-700" icon="mdi:circle" width="10" />
        <div class="">
          <span v-if="notificationType !== 'REMINDED'">
            {{ date }}
          </span>
          <span>
            {{ startEndTime }}
          </span>
        </div>
      </div>
      <div class="">
        <span v-if="notificationType === 'NEW'" :class="notificationTypeClass" class="notifyBadge">Янги топшириқ</span>
        <span v-if="notificationType === 'REMINDED'" :class="notificationTypeClass" class="notifyBadge">Эслатма</span>
        <span v-if="notificationType === 'EDITED'" :class="notificationTypeClass" class="notifyBadge">Топшириқ ўзгартирилди</span>
        <span v-if="notificationType === 'DELETED'" :class="notificationTypeClass" class="notifyBadge">Топшириқ бекор қилинди</span>
        <span v-if="notificationType === 'PRE_EVENT'" :class="notificationTypeClass" class="notifyBadge">Бошланғич топшириқ</span>
      </div>
    </div>
    <p :class="props.notifyContent.isImportant ? 'text-[#D55A00]' :'text-[#03A600]'">
      {{ props.notifyContent.title }}
    </p>
    <div class="flex justify-end text-gray-600">
      <span>{{ moment(notifyContent.createdAt).format('HH:mm ,  DD MMMM   YYYY') }}</span>
    </div>
  </div>
</template>

<script setup>
import {computed, defineComponent, defineProps, onMounted, ref} from "vue";
import {Icon} from "@iconify/vue";
import moment from "moment";
import {useRouter} from "vue-router";
import axios from "../plugins/axios";
defineComponent({Icon})

const props = defineProps({
  notifyContent:{
    default:function (){
      return {
        id:'',
        startTime:'',
        endTime:'',
        description:'',
      }
    },
  }
})
const emit = defineEmits(['notification-seen'])
const router = useRouter()
const startEndTime= computed(()=>{
  return moment(props.notifyContent.endTime).format('HH:mm')
})

const date= computed(()=>{
  return `${moment(props.notifyContent.date).format('DD MMMM ')}`
})

const notificationType = computed(()=>{
  return props.notifyContent.notificationType
})

const notificationTypeClass = computed(()=>{
  let type = notificationType.value
  return {
    'newType' : type === 'NEW' || type === 'PRE_EVENT',
    'editedType':  type === 'EDITED' || type === 'REMINDED',
    'deletedType':type === 'DELETED'
  }
})

function isToday(momentDate) {
  const TODAY = moment()
  return momentDate.isSame(TODAY, 'd');
}

async function seeNotification(){
  if(props.notifyContent.notificationType === 'PRE_EVENT'){
    await router.push('/create_event/'+props.notifyContent?.preEventId)
  }else{
    await router.push('/event/'+props.notifyContent?.eventId)
  }
  await axios.delete('/api/notification/'+ props.notifyContent.id)
  emit('notification-seen')
}


onMounted(()=>{

  // console.log(isToday(moment('2015-03-01')))
})

</script>

<style scoped>
.notifyBadge {
  border-radius: 0.375rem;
  padding-left: 8px;
  padding-right: 8px;
  padding-top: 2px;
  padding-bottom: 2px;
}
.newType {
  --tw-bg-opacity: 1;
  background-color: rgba(240, 253, 244, var(--tw-bg-opacity));
  --tw-text-opacity: 1;
  color: rgba(22, 163, 74, var(--tw-text-opacity));
}
.editedType {
  --tw-bg-opacity: 1;
  background-color: rgba(239, 246, 255, var(--tw-bg-opacity));
  --tw-text-opacity: 1;
  color: rgba(0, 123, 237, var(--tw-text-opacity));
}
.deletedType {
  --tw-bg-opacity: 1;
  background-color: rgba(253, 242, 248, var(--tw-bg-opacity));
  --tw-text-opacity: 1;
  color: rgba(236, 72, 153, var(--tw-text-opacity));
}
</style>