<template>
  <section class="flex flex-col h-full">
    <div class="px-4 flex items-center bg-[#DFE6FF] shadow-md sticky top-0 z-10 h-16">
      <Icon v-if="chatUsers.length" icon="mdi:keyboard-backspace" width="24" class="cursor-pointer" @click="deleteSelectedChatUser" />
      <ChatUserCard :user="selectedChatUser" />
    </div>
    <div class="chat px-2 overflow-y-scroll h-full">
      <infinite-loading direction="top" @infinite="load">
        <template #no-more>
          {{ ` ` }}
        </template>
        <template #no-results>
          {{ ` ` }}
        </template>
      </infinite-loading>
      <ChatMessage
        v-for="msg in messagesList" :id="msg.id" :key="msg.id"
        :message="msg.message" :is-mine="msg.isMine" :date="msg.date" :time="msg.time" :files="msg.files"
      />
    </div>
    <div class="bg-[#F4F4F4] flex items-center justify-around py-2">
      <FileInput :id="'chat'" :hide-files-list="true" @file-upload="setFiles">
        <template #input-icon>
          <Icon icon="mdi:paperclip" width="30" :rotate="2" :horizontal-flip="true" />
        </template>
      </FileInput>
      <textarea ref="textarea" v-model="message" class="py-3 px-[5px] mx-2 rounded h-10" style=" resize: none;" @keydown.enter.exact.prevent="sendMessage" @keydown.enter.shift.exact.prevent="message += '\n'" />
      <button @click="sendMessage">
        <Icon icon="mdi:send" class="text-blue-500" width="30" />
      </button>
    </div>
  </section>
  <ModalComponent
    ref="modalComponentRef"
    modal-position="center"
    :close-on-click-away="true"
    :hide-close-button="false"
    @close="onCloseModal"
  >
    <template #slotBody>
      <div v-if="uploadFiles.length" class="flex flex-wrap gap-4">
        <div v-for="f in uploadFiles" :key="f.thumb">
          <InputFileThumbWrapper :file-type="f.file.type" :file-source="f.thumb" :file-name="f.file.name" @delete-file="deleteSelectedFile" />
        </div>
      </div>
      <div class="flex justify-center">
        <button class="bg-primary px-3 py-2 text-white rounded-md" @click="sendChatFiles">
          Fayllarni yuborish
        </button>
      </div>
    </template>
  </ModalComponent>
</template>

<script setup>
import ChatUserCard from "../components/ChatUserCard";

import InfiniteLoading from 'vue-infinite-loading';
import {Icon} from "@iconify/vue";
import axios from "../plugins/axios";
import Badge from "../components/Badge";
import ChatMessage from "../components/ChatMessage";
import FileInput from "../components/FileInput";
import ModalComponent from "../components/ModalComponent";
import InputFileThumbWrapper from '../components/InputFileThumbWrapper'
import autosize from 'autosize'
import Chat from "../components/Chat";
import {defineComponent, defineProps, onMounted, ref, toRefs, watch} from "vue";
const modalComponentRef = ref();

defineComponent({ChatUserCard,Icon,Badge,ChatMessage,InfiniteLoading,FileInput ,ModalComponent,InputFileThumbWrapper,Chat})
const emit = defineEmits(['refresh-chat-counts','get-chat-new-messages','clear-selected-chat-user','chat-user-select','load-more-chat-messages'])

const props = defineProps({
  messagesList:{
    type:Array,
    default:function (){
      return []
    }
  },
  newMessagesCount:{
    type:Object,
    default:function (){
      return {
        allCount:0,
        bySender:[]
      }
    }
  },
  selectedChatUser:{
    type:[Object]
  },
  chatUsers:{
    type:Array
  }
})
const { messagesList , selectedChatUser } = toRefs(props)

const uploadFiles = ref([])

function setFiles(uploadedFiles){
  console.log('Chat')
  uploadFiles.value = uploadedFiles.map(f=>f.file)
}

onMounted(async()=>{
  autosize(document.querySelector('textarea'));
})

function deleteSelectedFile(thumb){
  uploadFiles.value = uploadFiles.value.filter((f)=>f.thumb !== thumb )
}


function onCloseModal(){
  uploadFiles.value = []
}

watch(()=>uploadFiles.value,(newVal,oldVal)=>{
  if(newVal.length && !oldVal.length){
    modalComponentRef.value.openModal()
  }
  if(!newVal.length && oldVal.length){
    modalComponentRef.value.closeModal()
  }
})

const textarea = ref(null)
const message = ref('')


function load(e){
  emit('load-more-chat-messages',e)
}
async function sendMessage(){
  if(message.value.trim()  === ''){
    return null
  }
  const blob = new Blob([JSON.stringify({
    message:message.value,
    receiverId:selectedChatUser.value.id
  }, null, 2)], { type: 'application/json' });

  const formData = new FormData()
  formData.append('dto',blob)
  await axios.post('/api/chat',formData)
  message.value = ''
  emit('get-chat-new-messages')
}

async function sendChatFiles(){
  const formData = new FormData()
  const blob = new Blob([JSON.stringify({
    message:null,
    receiverId:selectedChatUser.value.id
  }, null, 2)], { type: 'application/json' });
  formData.append('dto',blob)
  uploadFiles.value.forEach(f=>{
    formData.append('files',f.file)
  })
  await axios.post('/api/chat',formData)
  emit('get-chat-new-messages')
  uploadFiles.value = []
  modalComponentRef.value.closeModal()
}

async function deleteSelectedChatUser(){
  emit('clear-selected-chat-user',null)
}

watch(()=>textarea.value,async(val)=>{
  if(val){
    autosize(document.querySelector('textarea'));
  }
})


</script>

<style>

.chat::-webkit-scrollbar-track  {
  background-color: #e1e9f1;
}

.chat::-webkit-scrollbar-thumb {
  height: 30px;
  width: 5px;
  background-color: #d8dcdc;
}
.chat{
  scrollbar-color: #d8dcdc #e1e9f1;
  scrollbar-width:thin;
}

#autoresizing {
  display: block;
  overflow: hidden;
  resize: none;
}

</style>
