<template>
  <div class="h-full" style="height: 100% !important;">
    <div class="flex flex-col h-full">
      <div class="flex">
        <div class="tab_btn border-left" :class=" tabName === 'ActiveQueries' ? 'bg-blue-300 text-white' : 'bg-white' " @click="changeTab('ActiveQueries')">
          Актив
        </div>
        <div class="tab_btn  border-right" :class=" tabName === 'ArchivedQueries' ? 'bg-blue-300 text-white' : 'bg-white' " @click="changeTab('ArchivedQueries')">
          Архив
        </div>
      </div>
      <component :is="tab" :active-queries-list="activeQueriesList" @refresh-reports-count="emitRefreshReportsCount" @get-active-queries-list="emitGetActiveQueriesList" />
    </div>
  </div>
</template>

<script setup>
import {computed, defineProps, markRaw, ref,toRefs} from "vue";
import ArchivedQueries from "../components/ArchivedQueries";
import ActiveQueries from "../components/ActiveQueries";
import {useStore} from "vuex";
const emit = defineEmits(['refresh-reports-count','get-active-queries-list'])
const props = defineProps({
  activeQueriesList:{
    type:Array
  }
})

const {activeQueriesList} = toRefs(props)
const tab = ref(null)
const tabName = ref('ActiveQueries')
const store = useStore()
changeTab('ActiveQueries')
function emitGetActiveQueriesList(){
  emit('get-active-queries-list')
}
function emitRefreshReportsCount(){
  emit('refresh-reports-count')
}

async function changeTab  (newTab) {
  await  emit('get-active-queries-list')
  const lookup = {
    ArchivedQueries,
    ActiveQueries,
  }
  tabName.value  = newTab
  tab.value = markRaw(lookup[newTab])
}

const taskWindowSize = computed(()=>{
  let styleObject =  {}
  if(tabName.value === 'ActiveQueries'){
    if(store.getters['getUserInfo'].role.name === 'PREMIER_MINISTER' || store.getters['getUserInfo'].role.name === 'VICE_MINISTER' || store.getters['getUserInfo'].role.name === 'HEAD'){
      styleObject = {
        height : `calc(100% - 46px)`
      }
    }
    else if(store.getters['getUserInfo'].role.name === 'ASSISTANT_PREMIER'){
      styleObject = {
        height : `calc(100% - 120px)`
      }
    }
  }
  else if(tabName.value === 'ArchivedQueries'){
    styleObject = {
      height : `calc(100% - 46px)`
    }
  }
  return styleObject
})


</script>

<style scoped>
.tab_btn{
  @apply py-[10px] text-center w-1/2 border-white border cursor-pointer
}
</style>


