<template>
  <div v-click-away="closeDrop" class="relative inline-block text-left">
    <button
      id="menu-button"
      type="button"
      class="inline-flex justify-center items-center
       w-full rounded-md  px-4 py-2 text-sm font-medium text-gray-700  focus:outline-none"
      aria-expanded="true"
      aria-haspopup="true"
      @click.stop="toggleDrop"
    >
      <img
        :src="photoPath || logoUser"
        class="rounded-full object-cover w-12 h-12"
        alt=""
      >

      <svg
        v-if="isOpen" xmlns="http://www.w3.org/2000/svg" class="-mr-1 ml-2 h-4 w-4" fill="none" viewBox="0 0 24 24"
        stroke="currentColor"
      >
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 15l7-7 7 7" />
      </svg>
      <svg
        v-else xmlns="http://www.w3.org/2000/svg" class="-mr-1 ml-2 h-4 w-4" fill="none" viewBox="0 0 24 24"
        stroke="currentColor"
      >
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7" />
      </svg>
    </button>

    <div
      v-show="isOpen"
      style="z-index: 2000"
      class="origin-top-right absolute right-0 w-full min-w-42 rounded-md shadow-lg bg-white ring-1 ring-black ring-opacity-5 focus:outline-none z-20"
      role="menu" aria-orientation="vertical" aria-labelledby="menu-button" tabindex="-1"
    >
      <div class="py-1" role="none">
        <a
          id="menu-item-1" class="flex gap-2 items-center cursor-pointer text-gray-700 hover:text-white hover:bg-primary block px-5 py-2 text-sm" role="menuitem"
          tabindex="-1"
          @click.prevent="goToProfile"
        >
          <Icon icon="mdi:account-circle" width="20" />
          Профиль
        </a>
        <a
          id="menu-item-0" class="flex gap-2 items-center cursor-pointer text-gray-700 hover:text-white hover:bg-red-600 block px-5 py-2 text-sm" role="menuitem"
          tabindex="-1"
          @click.prevent="logout"
        >
          <Icon icon="mdi:logout" width="20" />
          Чиқиш
        </a>
        <!--        <a id="menu-item-1" href="#" class="text-gray-700 block px-4 py-2 text-sm" role="menuitem" tabindex="-1">-->
        <!--          O'zb-->
        <!--        </a>-->
        <!--        <a id="menu-item-2" href="#" class="text-gray-700 block px-4 py-2 text-sm" role="menuitem" tabindex="-1">Ўзб</a>-->
      </div>
    </div>
  </div>

  <!--
    Dropdown menu, show/hide based on menu state.

    Entering: "transition ease-out duration-100"
      From: "transform opacity-0 scale-95"
      To: "transform opacity-100 scale-100"
    Leaving: "transition ease-in duration-75"
      From: "transform opacity-100 scale-100"
      To: "transform opacity-0 scale-95"
  -->
</template>

<script>
import logoUser from "../assets/img/logoUser.png";
import axios from "../plugins/axios";
import {Icon} from "@iconify/vue";
export default {
  name: "ProfileDropdown",
  components: {
    Icon
  },
  data() {
    return {
      isOpen: false,
      logoUser,
      baseUrl:axios.defaults.baseURL.slice(0,axios.defaults.baseURL.length-1),
    };
  },
  computed:{
    photoPath:function (){
      if(this.$store.getters['getUserInfo'].photoPath){
        return this.baseUrl + this.$store.getters['getUserInfo'].photoPath
      }else {
        return null
      }
    }
  },
  methods: {
    toggleDrop() {
      this.isOpen = !this.isOpen;
    },
    closeDrop() {
      this.isOpen = false;
    },
    async goToProfile(){
      await this.$router.push('/profile')
      this.closeDrop()
    },
    async logout() {
      await axios.get("api/auth/logout");
      await this.$store.dispatch('toast', {
        message: 'Siz tizimdan chiqdingiz!',
        type: 'info'
      })
      await this.$router.push("/auth");

    }
  }
};
</script>

<style scoped></style>
