<template>
  <div class="flex items-center py-[10px] px-[15px] bg-[#DFE6FF] rounded-md" @click="$emit('clicked',user)">
    <img :src="photoUrl" class="rounded-full h-10 w-10 object-cover mr-5" alt="">
    <p class="truncate">
      {{ `${user?.lastName} ${user?.firstName} ${user?.fatherName || ''}` }}
    </p>
  </div>
</template>

<script>
import userPhoto from '../assets/logo.png'
import axios from "../plugins/axios";

export default {
  name: "ChatUserCard",
  props: {
    user: {
      type: Object,
      default: () => ({
        name: '',
        photo: '',
        id: ''
      })
    }
  },
  emits: ['clicked'],
  data() {
    return {
      photoUrl: this.user?.photo?.path ? axios.defaults.baseURL.slice(0, axios.defaults.baseURL.length - 1) + this.user?.photo?.path : userPhoto
    }
  }
}
</script>

