<template>
  <div @click="$emit('reply',message)">
    <div v-if="color === 'red'" style="max-width: 320px" class="p-[8px] min-h-8 relative flex items-center text-white text-center bg-[#ff7272] rounded-md cursor-pointer">
      <p class="break-words" style="max-width: 270px">
        {{ message }}
      </p>
      <span v-if="time" style="font-size: 11px" class="w-8 ml-2 text-white flex flex-col justify-end h-full">{{ showTime(time) }}</span>
    </div>
    <div v-if="color === 'yellow'" style="max-width: 320px" class="p-[8px] min-h-8 relative flex items-center text-white text-center bg-[#fda779] rounded-md cursor-pointer">
      <p class="break-words" style="max-width: 270px">
        {{ message }}
      </p>
      <span v-if="time" style="font-size: 11px" class="w-8 ml-2 text-white flex flex-col justify-end h-full">{{ showTime(time) }}</span>
    </div>
    <div v-if="color === 'green'" style="max-width: 320px" class="p-[8px] min-h-8 relative flex items-center text-gray-800 text-center bg-[#def9cd] rounded-md cursor-pointer">
      <p class="break-words" style="max-width: 270px">
        {{ message }}
      </p>
      <span v-if="time" style="font-size: 11px" class="w-8 ml-2 text-gray-800 flex flex-col justify-end h-full">{{ showTime(time) }}</span>
    </div>
  </div>
</template>

<script>
import moment from "moment";
export default {
  name: "ReplyMessage",
  props:{
    message:{
      type : String
    },
    color:{
      type : String
    },
    selectable:{
      type:Boolean
    },
    time:{
      type:String
    }
  },
  emits:['reply'],
  methods:{
    showTime(time){
      return moment(time).format('HH:mm')
    }
  }
}
</script>

<style scoped>

textarea{
  color: #def9cd;
