<template>
  <div ref="chatBlockRef" class="chat px-2 overflow-y-scroll h-full" style="height: 100% !important;">
    <infinite-loading direction="top" @infinite="load">
      <template #no-more>
        {{ ` ` }}
      </template>
      <template #no-results>
        {{ ` ` }}
      </template>
    </infinite-loading>
    <div v-for="task in archivedTaskList" :key="task.id">
      <div class="flex my-4 pr-8">
        <div class="bg-[#cfdefa] min-h-8 p-[8px] rounded-md relative flex items-center" style="max-width: 320px">
          <p class="break-words" style="max-width: 270px">
            {{ task.description }}
          </p>
          <span style="font-size: 11px" class="w-8 ml-2 text-gray-500 flex flex-col justify-end h-full">{{ slicedTime(task.createdAt) }}</span>
        </div>
      </div>
      <div class="flex justify-end my-4 pl-8">
        <ReplyMessage :message=" task.reply.message" :color="task.reply.color" :time="task.replyAt" />
      </div>
    </div>
  </div>
</template>

<script setup>

import axios from "../plugins/axios";
import {defineComponent, onMounted, ref} from "vue";
import InfiniteLoading from "vue-infinite-loading";
import ReplyMessage from "./ReplyMessage";
import moment from "moment";

const archivedTaskList = ref([])
defineComponent({InfiniteLoading,ReplyMessage})

const page = ref(1)

const load = async $state => {
  try {
    const resp  =  (await axios.get('/api/report/request/inactive',{
      params:{
        page:page.value,
        size:25
      }
    })).data.data
    if(!resp.content.length){
      $state.complete();
    }
    if(archivedTaskList.value.length === 0){
      archivedTaskList.value =  resp.content.reverse()
    } else {
      archivedTaskList.value =  [...resp.content.reverse(),... archivedTaskList.value]
    }
    page.value++;
    $state.loaded();
  } catch (error) {
    $state.complete();
  }
};

function slicedTime(time){
  return moment(time).format('HH:mm')
}

