<template>
  <div class="py-3 h-full">
    <section class="flex justify-around my-2 gap-4 sticky top-0 z-10">
      <button class="tab_btn relative" :class="selectedTabName === 'ChatView' ? 'bg-primary text-white':'bg-[#E5F2FD]'" @click="changeTab('ChatView')">
        Чат
        <Badge v-if="newMessagesCount && newMessagesCount.allCount" :content="newMessagesCount.allCount" />
      </button>
      <button class="tab_btn relative" :class="selectedTabName === 'TaskView' ? 'bg-primary text-white':'bg-[#E5F2FD]'" @click="changeTab('TaskView')">
        Топшириқ
        <Badge v-if="newTasksCount" :content="newTasksCount" />
      </button>
      <button class="tab_btn relative" :class="selectedTabName === 'QueryView' ? 'bg-primary text-white':'bg-[#E5F2FD]'" @click="changeTab('QueryView')">
        Сўров
        <Badge v-if="newRequestsCount" :content="newRequestsCount" />
      </button>
    </section>
    <section class="h-full tabContent">
      <ChatView
        v-if="selectedTabName ==='ChatView'"
        :messages-list="messagesList"
        :new-messages-count="newMessagesCount"
        @get-chat-new-messages="getNewMessages"
        @clear-selected-chat-user="clearSelectedChatUser"
        @refresh-chat-counts="getNewMessagesCount"
        @chat-user-select="setChatUser"
        @load-more-chat-messages="loadChatMessages"
      />
      <TaskView v-if="selectedTabName ==='TaskView'" :active-tasks-list="activeTasksList" @get-active-tasks-list="getActiveTasksList" @refresh-reports-count="getNewTasksAndRequestsCountByRole" />
      <QueryView v-if="selectedTabName ==='QueryView'" :active-queries-list="activeQueriesList" @get-active-queries-list="getActiveQueriesList" @refresh-reports-count="getNewTasksAndRequestsCountByRole" />
    </section>
  </div>
</template>

<script setup>
import ChatView from './ChatView'
import TaskView from './TaskView'
import QueryView from './QueryView'
import {computed, defineComponent, markRaw, nextTick, onMounted, ref, watch,onBeforeMount} from "vue";
import axios from "../plugins/axios";
import Badge from "../components/Badge";

defineComponent({
  ChatView,
  TaskView,
  QueryView,
  Badge
})

import {useStore} from "vuex";
import SockJS from "sockjs-client";
import Stomp from "webstomp-client";

const activeTasksList = ref([])
const activeQueriesList = ref([])

const selectedTabName = ref('ChatView')
const  store = useStore()

const userRole = computed(()=>store.getters['getUserInfo'].role.name)

async function getNewTasksAndRequestsCountByRole(){
  if(userRole.value === 'PREMIER_MINISTER' || userRole.value === 'VICE_MINISTER' || userRole.value === 'HEAD'){
    await getNewRequestsCount()
  }if(userRole.value === 'ASSISTANT_PREMIER' || userRole.value === 'ASSISTANT' || userRole.value === 'EMPLOYEE'){
    await getNewTasksCount()
  }
}

// async function getActiveTasksAndRequestsListByRole(){
//   if(userRole.value === 'PREMIER_MINISTER' || userRole.value === 'VICE_MINISTER' || userRole.value === 'HEAD'){
//     await getActiveTasksList()
//   }if(userRole.value === 'ASSISTANT_PREMIER' || userRole.value === 'ASSISTANT' || userRole.value === 'EMPLOYEE'){
//
//   }
// }

onMounted(async()=>{
   await getNewMessagesCount()
   await getActiveTasksList()
   await getActiveQueriesList()
   await getNewTasksAndRequestsCountByRole()
   await connectToReportsAndChat()
})

const tab = ref(null)

changeTab('ChatView')

function changeTab (newTab) {
  selectedTabName.value = newTab
  const lookup = {
    ChatView,
    TaskView,
    QueryView
  }
  tab.value = markRaw(lookup[newTab])
}

const page = ref(1)

const newMessagesCount = ref({
  allCount:0,
  bySender:[]
})

const newTasksCount = ref(null)
const newRequestsCount = ref(null)

const selectedChatUser = ref(null)

async function setChatUser(user){
  selectedChatUser.value = user
}
const messagesList = ref([])

async function clearSelectedChatUser(){
  messagesList.value = []
  page.value = 1
  selectedChatUser.value = null
}



async function getNewMessagesCount(){
  newMessagesCount.value = null
  newMessagesCount.value = (await axios.get('/api/chat/count')).data?.data
}
async function getNewTasksCount(){
  newTasksCount.value = null
  newTasksCount.value = (await axios.get('/api/report/task/count')).data?.data
}
async function getNewRequestsCount(){
  newRequestsCount.value = null
  newRequestsCount.value = (await axios.get('/api/report/request/count')).data?.data
}


async function getNewMessages(){
  const messagesIds = messagesList.value.map(m=>m.id)
  let resp =  (await axios.get('/api/chat',{
    params:{
      receiverId:selectedChatUser.value.id,
      page:1,
      size:25
    }
  })).data?.data
  let newMessages = resp.content?.filter(m=>!(messagesIds.includes(m.id)))
  messagesList.value = [...messagesList.value,...newMessages.reverse()]
  await nextTick()
  scrollToElemById(messagesList.value[messagesList.value.length-1].id)
}

async function getActiveTasksList(){
  activeTasksList.value = (await axios.get('/api/report/task/active')).data.data
  await nextTick()
  if(activeTasksList.value[activeTasksList.value.length-1]?.id){
    scrollToElemById(activeTasksList.value[activeTasksList.value.length-1].id)
  }
}

async function getActiveQueriesList(){
  activeQueriesList.value = (await axios.get('/api/report/request/active')).data.data
  await nextTick()
  if(activeQueriesList.value[activeQueriesList.value.length-1]?.id){
    scrollToElemById(activeQueriesList.value[activeQueriesList.value.length-1].id)
  }
}

function scrollToElemById(elemId){
  let elem =  document.getElementById(elemId)
  elem?.scrollIntoView({behavior: 'smooth', block: "center"});
}

const loadChatMessages = async $state => {
  try {
    let resp =  (await axios.get('/api/chat',{
      params:{
        receiverId:selectedChatUser.value.id,
        page:page.value,
        size:25
      }
    })).data.data
    if(!resp.content.length){
      $state.complete();
    }
    if(messagesList.value.length === 0){
      messagesList.value =  resp.content.reverse()
    } else {
      messagesList.value =  [...resp.content.reverse(),... messagesList.value]
    }
    page.value++;
    $state.loaded();
    await getNewMessagesCount()
  } catch (error) {
    $state.complete();
  }
};

async function connectToReportsAndChat() {
  let socket = new SockJS(`${axios.defaults.baseURL}socket`);
  let stompClient = Stomp.over(socket);
    await stompClient.connect(
        {},
        (frame) => {
          stompClient.subscribe(`/chat/${store.getters['getUserInfo'].id}`, async(tick) => {
            if(tick.body){
              const { message } = JSON.parse(tick.body)
              if(!selectedChatUser.value){
                notifyMe(message)
              }else {
                await getNewMessages()
              }
              await getNewMessagesCount()
            }
          });
          stompClient.subscribe(`/report/${store.getters['getUserInfo'].id}`, async(tick) => {
            if(tick?.body){
              const {type:reportType,message} = JSON.parse(tick.body)
                await getActiveTasksList()
                await getActiveQueriesList()
              notifyMe(message)
              await getNewTasksAndRequestsCountByRole()
            }
          });
        },
        error => {
          console.log(error);
        }
        );
}

function notifyMe(message) {
  // Проверка поддержки браузером уведомлений
  if (!("Notification" in window)) {
    alert("Ушбу браузерда хабарлар чиқариш имконияти мавжуд эмас");
  }

  // Проверка разрешения на отправку уведомлений
  else if (Notification.permission === "granted") {
    // Если разрешено, то создаём уведомление
    let notification = new Notification(message);
  }

  // В противном случае, запрашиваем разрешение
  else if (Notification.permission !== 'denied') {
    Notification.requestPermission(function (permission) {
      // Если пользователь разрешил, то создаём уведомление
      if (permission === "granted") {
        let notification = new Notification(message);
      }
    });
  }

  // В конечном счёте, если пользователь отказался от получения
  // уведомлений, то стоит уважать его выбор и не беспокоить его
  // по этому поводу.
}
</script>

<style scoped>
.tab_btn{
  @apply py-[8px] px-[12px] rounded-md focus:outline-none
}
.tabContent{
  height: calc(100% - 50px);
}
</style>