<template>
  <div class="h-full" style="height: 100% !important;">
    <section v-if="!selectedChatUser" class="flex flex-col px-2 gap-2">
      <div v-for="user in chatUsers" :key="user.name" class="relative">
        <ChatUserCard :user="user" class="cursor-pointer" @clicked="onSelectChatUser" />
        <Badge v-if="props.newMessagesCount && hasNewMessage(user.id)" :content="findCountBySenderId(user.id)" badge-position="-top-2 right-2" />
      </div>
    </section>
    <Chat
      v-if="selectedChatUser"
      :selected-chat-user="selectedChatUser"
      :chat-users="chatUsers"
      :messages-list="messagesList"
      @load-more-chat-messages="$emit('load-more-chat-messages',$event)"
      @refresh-chat-counts="$emit('refresh-chat-counts',$event)"
      @get-chat-new-messages="$emit('get-chat-new-messages',$event)"
      @chat-user-select="$emit('chat-user-select',$event)"
      @clear-selected-chat-user="clearSelectedChatUser"
    />
  </div>
</template>
<script setup>

import {defineComponent, onMounted, ref, onBeforeUnmount, defineProps, toRefs} from 'vue'
import ChatUserCard from "../components/ChatUserCard";
import InfiniteLoading from 'vue-infinite-loading';
import axios from "../plugins/axios";
import Badge from "../components/Badge";
import {useStore} from "vuex";
import Chat from "../components/Chat";


defineComponent({ChatUserCard,Badge,InfiniteLoading ,Chat})
const emit = defineEmits(['refresh-chat-counts','get-chat-new-messages','clear-selected-chat-user','chat-user-select','load-more-chat-messages'])
const props = defineProps({
  messagesList:{
    type:Array,
    default:function (){
      return []
    }
  },
  newMessagesCount:{
    type:Object,
    default:function (){
      return {
        allCount:0,
        bySender:[]
      }
    }
  }
})
const { messagesList } = toRefs(props)


onMounted(async()=>{
  await getChatters()
})

onBeforeUnmount(()=>{
  selectedChatUser.value = null
  emit('clear-selected-chat-user')
})

async function clearSelectedChatUser(){
  selectedChatUser.value = null
  emit('clear-selected-chat-user',null)
}


function findCountBySenderId(id){
  return props.newMessagesCount.bySender.filter(s=>s.senderId === id)[0].count
}
function hasNewMessage(id){
   return  !!props.newMessagesCount.bySender.filter((sender)=>sender.senderId === id)[0]
}

const chatUsers = ref([])

async function getChatters(){
  const resp = (await axios.get('/api/user/chatter')).data?.data
  if (resp.length === 1){
    selectedChatUser.value = resp[0]
    emit('chat-user-select',resp[0])
  } else {
    chatUsers.value = resp
  }
}

const selectedChatUser = ref(null)
const store = useStore()


async function onSelectChatUser(user){
  selectedChatUser.value = user
  emit('chat-user-select',user)
}

</script>