<template>
  <div
      class="h-screen relative z-10 bg-gray-50 shadow w-24 transition-all duration-100 ease-in overflow-hidden"
      :class="{ 'w-80': sidebarIsOpen }"
  >
    <div class="px-3 my-8 flex flex-col">
      <p class="px-2 text-center text-sm  text-gray-700">
        Ўзбекистон Республикаси Маданият вазирлиги
      </p>
      <!--      <NavToggle />-->
    </div>
    <ul class="px-2">
      <router-link
          v-for="link in sideBars"
          :key="link.title"
          :to="link.path"
          tag="li"
          class="flex items-center flex-wrap cursor-pointer mb-3 p-2 text-gray-500 rounded-md"
          @click.stop
      >
        <div class="my-list">
          <Icon :icon="link.iconName" class="w-8 h-8"/>
          <p class="ml-2">
            {{ link.title }}
          </p>
        </div>
      </router-link>
    </ul>
  </div>
</template>

<script setup>
import sidebarLinks from "../services/sidebarLinks";
import NavToggle from "./NavToggle";

import {computed, defineComponent, onMounted, onUnmounted, ref} from "vue";
import {useStore} from "vuex";
import {Icon} from '@iconify/vue';
import {useRouter} from "vue-router";
import axios from "@/plugins/axios";
import autosize from "autosize";
import moment from "moment/moment";

const sidebarIsOpen = ref(true)
const sideBars = ref([])
const store = useStore()
const router = useRouter()


onMounted(async () => {
  sideBars.value = sidebarLinks[store.getters['getUserInfo'].role.name]
  if (store.getters['getUserInfo'].role.name === 'PREMIER_MINISTER') {
    const resp = (await axios.get('api/user/vice')).data
    resp.data.map((n, i) => {
      sideBars.value.push({
        iconName: 'mdi:account',
        title: n.lastName + " " + n.firstName + " " + n.fatherName,
        path: '/vice/' + n.id
      })
    })
  }
})

onUnmounted(async () => {
  sideBars.value = sidebarLinks[store.getters['getUserInfo'].role.name]
})


defineComponent({
  NavToggle,
  Icon
})
// const toggleSidebar = () => {
//   console.log("toggled");
//   this.sidebarIsOpen = !this.sidebarIsOpen;
// };

</script>


