<template>
  <div ref="chatBlockRef" class="chat px-2 overflow-y-scroll h-full">
    <div v-for="query in activeQueriesList" :id="query.id" :key="query.id">
      <div class="flex my-4 justify-end">
        <div
            style="max-width: 320px"
            class="bg-[#cfdefa] min-h-8 p-[8px] rounded-md relative flex items-center"
            :class="role === 'PREMIER_MINISTER' || role === 'VICE_MINISTER' || role === 'HEAD' ? 'cursor-pointer':''"
            @click.right.prevent="showMessageDropdown(query.id,query.createdBy)"
            @click.left.stop="replyMessage(query.id)"
        >
          <div v-if="messageModalId === query.id" v-click-away="clearMessageModal" class="absolute top-3 right-10  z-60 rounded-md shadow bg-gray-100 py-2" @click.stop>
            <div class="cursor-pointer flex gap-4 items-center hover:text-white hover:bg-primary px-3 py-1" @click="editMessage(query.description,query.id)">
              <Icon icon="mdi:pencil" width="20" /> Edit
            </div>
            <div class="cursor-pointer flex gap-4 items-center hover:text-white hover:bg-primary px-3 py-1" @click="openDeleteModal(query.id)">
              <Icon icon="mdi:delete" width="20" /> Delete
            </div>
          </div>
          <p class="break-words" style="max-width: 270px">
            {{ query.description }}
          </p>
          <span style="font-size: 11px" class="w-8 ml-2 text-gray-500 flex flex-col justify-end h-full">{{ slicedTime(query.createdAt) }}</span>
          <div
              v-if="repliedMessageId === query.id"
              v-click-away="clearRepliedMessage"
              class="absolute top-2 right-10 p-2 w-[260px] bg-white shadow rounded-md flex flex-col gap-2 z-30" @click.stop
          >
            <ReplyMessage v-for="replyMsg in replyMessages" :key="replyMsg" :message="replyMsg.message" :color="replyMsg.color" @reply="sendRepliedMessage" />
            <select class="text-center" @input="sendNotifyTime">
              <option value="null">
                Кейинроқ эслатилсин!
              </option>
              <option value="10">
                10 минут
              </option>
              <option value="20">
                20 минут
              </option>
              <option value="30">
                30 минут
              </option>
              <option value="60">
                1 соат
              </option>
            </select>
          </div>
        </div>
      </div>
      <div class="flex my-4">
        <ReplyMessage :message="query?.reply?.message" :color="query?.reply?.color" :time="query?.replyAt" />
      </div>
    </div>
  </div>
  <div v-if="editMode" class="h-14 px-3 w-full bg-gray-100 p-1 shadow">
    <div class="flex justify-between">
      <div class="flex items-center gap-3">
        <h1 class="text-sm text-primary">
           Таҳрирлаш
        </h1>
        <Icon class="text-primary" icon="mdi:pencil" width="12" />
      </div>
      <button @click.prevent="cancelEditing">
        <Icon icon="ic:round-cancel" width="20" />
      </button>
    </div>
    <p class="line-clamp-1">
      {{ editedMessageText }}
    </p>
  </div>
  <div v-if="role === 'ASSISTANT_PREMIER' || role === 'ASSISTANT' || role === 'EMPLOYEE'" class="bg-[#F4F4F4] flex items-center justify-around py-2">
    <textarea ref="textAreaRef" v-model="message" class="py-3 px-[5px] w-full rounded h-12" style="resize: none;" @keydown.enter.exact.prevent="sendMessage" @keydown.enter.shift.exact.prevent="message += '\n'" />
    <button v-if="editMode" @click="sendEditedMessage">
      <Icon icon="mdi:check-bold" width="30" class="text-blue-500" />
    </button>
    <button v-else @click="sendMessage">
      <Icon icon="mdi:send" class="text-blue-500" width="30" />
    </button>
  </div>
  <ModalComponent
    ref="modalComponentRef"
    modal-position="center"
    :close-on-click-away="true"
    :hide-close-button="false"
  >
    <template #slotBody>
      <div class="p-10 text-3xl flex items-center justify-center">
        <h1>Сиз топшириқни ўчирмоқчимисиз?</h1>
      </div>
      <div class="flex justify-center">
        <button class="base_input border-primary bg-primary text-white mx-2 hover:opacity-80" @click="modalComponentRef.closeModal">
          Йўқ
        </button>
        <button class="base_input border-primary bg-primary text-white mx-2 hover:opacity-80" @click="deleteMessage">
          Ҳа
        </button>
      </div>
    </template>
  </ModalComponent>
</template>

<script setup>

import {Icon} from "@iconify/vue";
import axios from "../plugins/axios";
import {computed, defineComponent, defineEmits, defineProps, nextTick, onMounted, ref, toRefs} from "vue";
import ChatMessage from "../components/ChatMessage";
import FileInput from "../components/FileInput";
import ModalComponent from "../components/ModalComponent";
import InputFileThumbWrapper from "../components/InputFileThumbWrapper";
import {useStore} from "vuex";
import moment from "moment";
import ReplyMessage from "./ReplyMessage";
import autosize from 'autosize'
import SockJS from "sockjs-client";
import Stomp from "webstomp-client";
const repliedMessageId=ref(null)



const emit = defineEmits(['refresh-reports-count','get-active-queries-list'])
const props = defineProps({
  activeQueriesList:{
    type:Array
  }
})
defineComponent({Icon,ChatMessage,FileInput ,ModalComponent,InputFileThumbWrapper,ReplyMessage})

onMounted(async()=>{
  await  getQueryReplyMessages()
  autosize(document.querySelector('textarea'));
})
const {activeQueriesList} = toRefs(props)

const editMode = ref(false)
const messageModalId = ref(null)
const editingMessageId = ref(null)
const deletingMessageId = ref(null)
const editedMessageText = ref(null)
const modalComponentRef = ref()


const textAreaRef = ref()
const openDeleteModal = (id)=>{
  modalComponentRef.value.openModal()
  deletingMessageId.value = id
}



const replyMessages = ref(null)

async function getQueryReplyMessages(){
  replyMessages.value =  (await axios.get('/api/info/request-reply')).data
}

async function sendNotifyTime(e){
  await sendRepliedMessage(null,e.target.value)
}

const message = ref('')


const store = useStore()



const role = computed(()=>store.getters['getUserInfo'].role.name )
const userId = computed(()=>store.getters['getUserInfo'].id)



function showMessageDropdown(id,createdBy){
  if(createdBy !== userId.value){
    return null
  }
  messageModalId.value = id
}

function editMessage(editableMessage,messageId){
  editMode.value = true
  clearMessageModal()
  editingMessageId.value = messageId
  message.value = editableMessage
  editedMessageText.value = editableMessage
  textAreaRef.value.focus()
}

async function deleteMessage() {
  try {
    const resp =  (await axios.delete(`/api/report/${deletingMessageId.value}`)).data
    await store.dispatch('toast',{
      type:'success',
      message:resp.message
    })
    modalComponentRef.value.closeModal()
    emit('get-active-queries-list')
    emit('refresh-reports-count')
  }catch (e) {
    await store.dispatch('errorHandler',e)
  }
}

function cancelEditing(){
  editMode.value = false
  editingMessageId.value = false
  editedMessageText.value = ''
  message.value = ''
}

function clearMessageModal(){
  messageModalId.value = null
}



function slicedTime(time){
  return moment(time).format('HH:mm')
}

function clearRepliedMessage(){
  repliedMessageId.value = null
}

function replyMessage(messageId){
  if(role.value === 'ASSISTANT_PREMIER'){
    return null
  }
  if(repliedMessageId.value === messageId){
    clearRepliedMessage()
  }else repliedMessageId.value = messageId
}

async function sendRepliedMessage(message,notifyTime=null){
  try {
    await axios.post('/api/report/reply',{
      reply: message,
      notifyTime: notifyTime,
      reportId : repliedMessageId.value
    })
    clearRepliedMessage()
    emit('get-active-queries-list')
    emit('refresh-reports-count')
  }catch (e) {
    await store.dispatch('errorHandler',e)
  }
}

async function sendMessage(){
  if(editMode.value){
    return sendEditedMessage()
  }
  if(message.value.trim() === ''){
    return null
  }
  await axios.post('/api/report',{
    description:message.value
  })
  message.value=''
  emit('get-active-queries-list')
}
async function sendEditedMessage(){
  if(message.value.trim() === ''){
    return null
  }
  await axios.put(`/api/report/${editingMessageId.value}`,{
    description:message.value
  })
  message.value=''
  emit('get-active-queries-list')
  cancelEditing()
}



</script>

